@Component({
  selector: 'page-casefile',
  templateUrl: 'casefile.html',
})
export class CaseFilePage {

  casefile: any;
  court: any;
  account: any;
  caselaws: boolean;
  legislation: boolean;
  hamburger: boolean;
  peshi: boolean;
  baseUrl: string;
  currentPageIndex: number;
  currentPageIndexForFlag: number;
  removedItems: Array<string>;
  additionalRemovedItems: Array<string>;
  options: any;
  welcomeString : string;
  currentDoc: string;
  paths: Array<string>;
  orderType: Array<string>;
  showFlag : boolean;
  constructor(public navCtrl: NavController, public navParams: NavParams, public sanitizer: DomSanitizer, public modalCtrl: ModalController) {
    this.currentPageIndex = 0;
    this.currentPageIndexForFlag = 0;
    this.caselaws = false;
    this.legislation = false;
    this.peshi = false;
    this.showFlag = false;
    this.casefile = this.navParams.get('casefile');
    this.court = this.navParams.get('court');
    this.account = this.navParams.get('account');
    this.currentDoc = 'Case File';
    console.log(this.casefile, this.casefile['caseNo']);
    this.baseUrl = 'https://courtdesk.github.io';
    // this.baseUrl = 'http://127.0.0.1:8080';
    this.removedItems = ["pan", "ink-signature", "text" , "image", "stamp", "line", "rectangle", "arrow", "ellipse", "polygon", "polyline"];
    this.additionalRemovedItems = ["annotate", "ink", "highlighter", "note"];
    if (this.account.type == "cs") {
      this.removedItems = this.removedItems.concat(this.additionalRemovedItems);
    }
    this.orderType = ["Final","Draft"];

    if(this.account.type == 'judge')
      this.welcomeString = 'HMJ SB';
    else if(this.account.type == 'cs'){
      this.orderType.pop();
      this.welcomeString = 'Court Staff';
    }
    else if(this.account.type == 'lr')
      this.welcomeString = 'LR';

    this.options = [
      {
        name : "Case File",
        submenus: [],
        icon : this.baseUrl + "/assets/icon/" + "casefile.svg"
      },
      {
        name: "Peshi",
        submenus: [],
        icon : this.baseUrl + "/assets/icon/" + "peshi.png"
      },
      {
        name: "Case Laws",
        submenus: this.casefile.caselaws,
        icon : this.baseUrl + "/assets/icon/" + "caselaws.png"
      },
      {
        name : "Legislations",
        submenus: this.casefile.legislations,
        icon : this.baseUrl + "/assets/icon/" + "legislation.png"
      },
      {
        name : "Orders",
        submenus: this.orderType,
        icon : this.baseUrl + "/assets/icon/" + "peshi.png"
      }
    ];
    // console.dir(PSPDFKit);

  }

  ionViewDidLoad() {
    // console.log('ionViewDidLoad CasepagePage');
    this.init();

  }


  initPath(){
    this.paths = [ "Court Room "+this.court.courtNumber, this.casefile['caseNo']];
  }

  init() {
    this.initPath();
    this.caselaws = false;
    this.legislation = false;
    this.peshi = false;
    this.loadPDF("casefile.pdf");
  }

  loadPDF(file) {
    let $this = this;

    this.clearPDF();
    let filePath = encodeURI(this.casefile['caseNo']) + "/" + file;
    const defaultItems = PSPDFKit.defaultToolbarItems;
    if(file === "casefile.pdf" && this.account.type == "lr"){
      this.removedItems = this.removedItems.concat(this.additionalRemovedItems);
    }
    PSPDFKit.load({
      container: "#pspdfkit",
      pdf: this.baseUrl + "/assets/docs/" + filePath,
      instantJSON: JSON.parse(localStorage.getItem(filePath)),
      licenseKey: "Q9diEIjbVwUtQKYioXpPO5TY-_uZcFJN1CfxpoEazlC0EvN9BpMSe_KSvgNrOYr39D2Got3XhvpvIjayZPsyQQNrPlLilbKxSkrc-_dZ_OAxucdWJMiGaSQWNAgOOWLwYAPv3ssjsNMupdNIer37PY-zvtXRqtK_aNoHfZnfx5eZI7CdQP5BZWbxMSM-rZYGxgXxHMKajEWP5H_uXihdZWCcNrFymnOd2qsGP8b04vh_SP3STVJ61C7VnB9CRsqJsBF46OBKWluz7vpebSlSxeqZBCZh1sMfQbd_C3hRHgJSUif9Nn35878_JEFYeYUbD_pu9NGMeWYGjCGAWHxv_DTRFd9-wCevJ8FlDN5P7ZTHSOdUHEgUfkUP_8upLJvp8eCdv4U4-m0Jwt1G_YTiaW03YQVS_QFjsaAgrtMVvuvmh7fyk5USsT5xLuuJ1of1",
      disableWebAssemblyStreaming: true
    })
      .then(instance => {
        instance.setViewState(viewState =>
          viewState.set("sidebarMode", PSPDFKit.SidebarMode.ANNOTATIONS)
        );

        if (file === "casefile.pdf") {
          instance.setViewState(viewState =>
            viewState.set("currentPageIndex", this.currentPageIndex)
          );
        }
        const toolbarItems = PSPDFKit.defaultToolbarItems;
        const index = toolbarItems.findIndex(item => item.type === "annotate");

        let flagButton = document.getElementById("flag-button");
        flagButton.classList.add("show-flag");
        flagButton.onclick = function(){
            const bookmark = new PSPDFKit.Bookmark({
              name: 'Flagged-' +  ($this.currentPageIndexForFlag+1),
              action: new PSPDFKit.Actions.GoToAction({ pageIndex:  $this.currentPageIndexForFlag })
            });

            instance.createBookmark(bookmark);
          
        }
          


        instance.setToolbarItems(items =>
          items.map(item => {
            console.log(item);
            if (this.removedItems.indexOf(item.type) > -1)
              item.mediaQueries = ['(min-width: 8000px)'];
            else
              item.mediaQueries = ['(min-width: 10px)'];

            if (item.type == "ink" || item.type == "highlighter")
              item['dropdownGroup'] = UUID.UUID();

            item['responsiveGroup'] = UUID.UUID();
            return item;
          })
        );

        console.log(toolbarItems[index].onPress);
        console.log(instance);
        instance.addEventListener("viewState.change", (viewState) => {
          if (file === "casefile.pdf")
            this.currentPageIndex = viewState.get('currentPageIndex');
        });

        instance.addEventListener("viewState.currentPageIndex.change", (pageIndex) => {
          this.currentPageIndexForFlag = pageIndex;
        });

        instance.addEventListener("annotations.didSave", async () => {
          // const instantJSON = await instance.exportInstantJSON();
          // console.log(JSON.stringify(instantJSON));
          // await fetch("http://127.0.0.1:8001", {
          //   method: "POST",
          //   headers: {
          //     "Content-Type": "application/json"
          //   },
          //   body: JSON.stringify(instantJSON)
          // });
          instance.exportInstantJSON().then(instantJSON => {
            localStorage.setItem(filePath, JSON.stringify(instantJSON));
          });
        });

        instance.addEventListener("bookmarks.didSave", async () => {
          // const instantJSON = await instance.exportInstantJSON();
          // console.log(JSON.stringify(instantJSON));
          // await fetch("http://127.0.0.1:8001", {
          //   method: "POST",
          //   headers: {
          //     "Content-Type": "application/json"
          //   },
          //   body: JSON.stringify(instantJSON)
          // });
          instance.exportInstantJSON().then(instantJSON => {
            localStorage.setItem(filePath, JSON.stringify(instantJSON));
          });
        });
      })
      .catch(error => {
        console.error(error.message);
      });
  }

  close() {
    this.navCtrl.pop();
  }

  hideBar() {
    this.caselaws = false;
    this.legislation = false;
    this.init();
  }

  showBar(type) {
    if (type == 'caselaws') {
      this.caselaws = true;
      this.legislation = false;
    }
    else {
      this.legislation = true;
      this.caselaws = false;
    }

  }

  openCaseLaw(caselaw) {
    this.peshi = false;
    this.loadPDF("Caselaw/" + caselaw)
  }

  openLegislation(legislation) {
    this.peshi = false;
    this.loadPDF("Legislations/" + legislation)
  }

  viewPeshi() {
    this.loadPDF("peshi.pdf");
    this.peshi = true;
  }

  clearPDF() {
    const parent = document.getElementById("pspdfkit");
    while (parent.firstChild) {
      parent.firstChild['remove']();
    }
  }

  fullscreen() {
    const elem = document.getElementById("pspdfkit");
    if (elem.requestFullscreen) {
      elem.requestFullscreen();
    } else if (elem['mozRequestFullScreen']) { /* Firefox */
      elem['mozRequestFullScreen']();
    } else if (elem['webkitRequestFullscreen']) { /* Chrome, Safari and Opera */
      elem['webkitRequestFullscreen']();
    } else if (elem['msRequestFullscreen']) { /* IE/Edge */
      elem['msRequestFullscreen']();
    }
  }

  uploadCaseLaw() {
    let modal = this.modalCtrl.create(UploadCaselawModal, { casefile: this.casefile });
    modal.present();
  }

  uploadLegislation() {
    let modal = this.modalCtrl.create(UploadLegislationModal, { casefile: this.casefile });
    modal.present();
  }

  draftPeshi() {
    let modal = this.modalCtrl.create(DraftPeshiModal, { casefile: this.casefile });
    modal.present();
  }

  draftOrder(order) {
    let modal = this.modalCtrl.create(DraftOrderModal, { account: this.account, order: order });
    console.log('yoo');
    modal.present();
  }

   hideAll(currEle){
    var allEls = Array.from(document.querySelectorAll('p.header'));
    allEls.forEach(function(el){
      if(el!=currEle){
        var innerWrapper = el.nextElementSibling;
        el.classList.remove('active');
        innerWrapper.classList.remove('visible-items');
      }        
    });

  }
  ngIfCtrl(ev,name){
    this.initPath();
    this.currentDoc = name;
    var currEle = ev.target.closest('.header');
    this.hideAll(currEle);
    var innerWrapper = currEle.nextElementSibling;
    currEle.classList.toggle('active');
    innerWrapper.classList.toggle('visible-items');
    if(name == 'Peshi')
      this.viewPeshi();
    else if(name == 'Case File')
        this.init();
  }  

  openDocument(doc,name){
    this.initPath();
    this.currentDoc = doc;
    if(name == 'Case Laws'){
      this.openCaseLaw(doc);
      this.paths.push(name);
    }else if(name == 'Legislations'){
      this.openLegislation(doc);
      this.paths.push(name);
    }else if(name == 'Orders'){
      this.draftOrder(doc);
    }
  }

  uploadNew(name){
     if(name == 'Case Laws'){
      this.uploadCaseLaw();
    }else if(name == 'Legislations'){
      this.uploadLegislation();
    }
  }
}



@Component({
  selector: 'page-upload-caselaw',
  templateUrl: 'upload-caselaw.html',
})
export class UploadCaselawModal {
  // @ViewChild('files') files: ElementRef;

  casefile: any;
  caselaw: { title: string, citation: string } = {
    title: '',
    citation: ''
  };
  file: any;
  caseLawName: any;
  fileWrapper: any;
  fileInput: any;
  account: any;
  constructor(public navCtrl: NavController, public navParams: NavParams, public viewCtrl: ViewController, public toastCtrl: ToastController) {
    this.casefile = this.navParams.get('casefile');
  }

  ionViewDidLoad() {
    let $this = this;
    this.fileInput = document.querySelector('input[type=file]');
    this.fileWrapper = document.querySelector('#fileUpload .input-wrapper');
    this.fileWrapper.onclick = function() {
      $this.fileInput.click();
    }
    this.fileInput.onchange = function() {
      $this.file = $this.fileInput.files[0];
      $this.caseLawName = $this.file.name;
    }
  }

  dismiss() {
    this.viewCtrl.dismiss();
  }

  save($event) {
    $event.preventDefault();
    this.casefile.caselaws.push(this.caselaw.title);
    let toast = this.toastCtrl.create({
      message: 'Login Success',
      duration: 3000,
      position: 'top'
    });
    toast.present();
    this.dismiss();
    // console.log(this.fileInput.files[0]);
  }

}


